noncompliant:
#include <cstdlib>
#include <iostream>

// Noncompliant: Function never returns but not marked as noreturn
void fatalError(const char* message) {
    std::cerr << "Fatal error: " << message << std::endl;
    exit(1);
    // Function never reaches here
}

// Another noncompliant example
void terminateProgram() {
    std::terminate();  // Never returns
    // Missing noreturn attribute
}

// Noncompliant: Function that always throws
void handleCriticalError() {
    throw std::runtime_error("Critical error occurred");
    // Never returns normally
}

compliant:
#include <cstdlib>
#include <iostream>

// Compliant: Function marked with noreturn attribute
[[noreturn]] void fatalError(const char* message) {
    std::cerr << "Fatal error: " << message << std::endl;
    exit(1);
}

// Another compliant example using C++11 attribute
[[noreturn]] void terminateProgram() {
    std::terminate();
}

// Compliant: Function that always throws marked as noreturn
[[noreturn]] void handleCriticalError() {
    throw std::runtime_error("Critical error occurred");
}

// Usage example showing compiler optimization
int processValue(int value) {
    if (value < 0) {
        fatalError("Negative values not allowed");
        // Compiler knows this code is unreachable
    }
    return value * 2;  // No need for else clause
}
